import{_ as t,c as n,o,a5 as a,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.23: Desktop New Layout and Chinese Text Rendering Fix","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.23.md","filePath":"en/changelog/v1.1.23.md","lastUpdated":1772014034000}'),r={name:"en/changelog/v1.1.23.md"};function s(l,i,d,p,h,c){return o(),n("div",null,[...i[0]||(i[0]=[a('<h1 id="v1-1-23-desktop-new-layout-and-chinese-text-rendering-fix" tabindex="-1">v1.1.23: Desktop New Layout and Chinese Text Rendering Fix <a class="header-anchor" href="#v1-1-23-desktop-new-layout-and-chinese-text-rendering-fix" aria-label="Permalink to “v1.1.23: Desktop New Layout and Chinese Text Rendering Fix”">​</a></h1><p><strong>Release Date</strong>: January 16, 2026</p><hr><h2 id="one-line-summary" tabindex="-1">One-Line Summary <a class="header-anchor" href="#one-line-summary" aria-label="Permalink to “One-Line Summary”">​</a></h2><p>This update brings a brand new desktop layout design, fixes Chinese text rendering issues in terminal, and optimizes link opening behavior.</p><hr><h2 id="new-feature-desktop-revamped" tabindex="-1">New Feature: Desktop Revamped <a class="header-anchor" href="#new-feature-desktop-revamped" aria-label="Permalink to “New Feature: Desktop Revamped”">​</a></h2><h3 id="what-s-updated" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>OpenCode desktop app has undergone a visual and experience upgrade, adopting a brand new application layout and optimizing numerous UI details.</p><h3 id="detail-optimizations" tabindex="-1">Detail Optimizations <a class="header-anchor" href="#detail-optimizations" aria-label="Permalink to “Detail Optimizations”">​</a></h3><ul><li><strong>Brand new layout</strong>: Interface is cleaner and more modern, operations smoother</li><li><strong>State memory</strong>: Now automatically remembers your workspace branch selection, file list sorting and collapsed state, next time it opens just as you left it</li><li><strong>Visual tweaks</strong>: Fixed thinking animation opacity, session icon alignment, background color and other detail issues</li></ul><h3 id="how-to-experience" tabindex="-1">How to Experience? <a class="header-anchor" href="#how-to-experience" aria-label="Permalink to “How to Experience?”">​</a></h3><p>Just upgrade to the latest OpenCode desktop app to see the changes.</p><hr><h2 id="improvement-chinese-text-rendering-fix" tabindex="-1">Improvement: Chinese Text Rendering Fix <a class="header-anchor" href="#improvement-chinese-text-rendering-fix" aria-label="Permalink to “Improvement: Chinese Text Rendering Fix”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>In terminal interface (TUI), Chinese, Japanese and other wide characters (CJK) sometimes had line break errors or rendering overlap issues, affecting reading experience.</p><h3 id="current-behavior" tabindex="-1">Current Behavior <a class="header-anchor" href="#current-behavior" aria-label="Permalink to “Current Behavior”">​</a></h3><p>Upgraded underlying display library (OpenTUI v0.1.73), completely fixing these issues. Now viewing Chinese content in terminal, the layout is more neat and beautiful.</p><hr><h2 id="improvement-link-navigation-optimization" tabindex="-1">Improvement: Link Navigation Optimization <a class="header-anchor" href="#improvement-link-navigation-optimization" aria-label="Permalink to “Improvement: Link Navigation Optimization”">​</a></h2><h3 id="previous-issue-1" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-1" aria-label="Permalink to “Previous Issue”">​</a></h3><p>Clicking links in desktop app (like documentation links) sometimes opened in a small window within the app, browsing experience not good enough, also couldn&#39;t use browser plugins.</p><h3 id="current-behavior-1" tabindex="-1">Current Behavior <a class="header-anchor" href="#current-behavior-1" aria-label="Permalink to “Current Behavior”">​</a></h3><p>Now clicking external links directly opens in your system&#39;s default browser.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td><strong>Chinese user</strong></td><td>✅ <strong>Strongly recommended upgrade</strong> (text rendering fixed)</td></tr><tr><td>Desktop user</td><td>✅ Recommended upgrade (new layout better)</td></tr><tr><td>Command line user</td><td>Recommended upgrade</td></tr></tbody></table><p><strong>Upgrade Command</strong>:</p>',29),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),a('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full changelog</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Ensure agent exists before processing title in session summary</li><li>More defensive handling of project list to prevent errors</li><li>Filter dead worktrees from git worktree list</li><li>Load models.dev in development mode</li><li>Ensure frontmatter can process same content as other agents</li><li>Show toast error message when ConfigMarkdown parsing fails</li><li>Prettify retry duration display in TUI</li><li>Handle broken symlinks gracefully in grep tool</li><li>Honor per-server MCP timeouts</li><li>Upgrade OpenTUI to v0.1.73, fixing CJK word wrapping</li><li>Add input limit for compaction</li><li>Fix Codex ID issue</li><li>Revert provider-level store option</li><li>Allow provider-level store option</li><li>Make dialog keybinds configurable</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Update black plan selection with light rays effect and mobile styles</li><li>Use native text truncation for sidebar diff paths</li><li>Center the initially selected session in the session list</li><li>Restore brand integrity of TUI wordmark</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Fix sidebar toggle on desktop</li><li>Persist workspace branch selection across sessions</li><li>Persist workspace order and collapsed state in sidebar</li><li>Fix thinking animation opacity and improve design</li><li>Fix session icon and name alignment</li><li>Show session as busy even when it&#39;s the active session</li><li>Stop killing opencode-cli process on dev mode restart</li><li>Update desktop question tools</li><li>Fix current session background color</li><li>Remove the active state from load more button after press</li><li>Fix new session tooltip position and add keyboard shortcut</li><li>Remove more options tooltip</li><li>Fix workspace name color in UI</li><li>Hide &quot;View all sessions&quot; button when on active project page</li><li>Fix avatar button states</li><li>Reduce font size of load more button</li><li>Fix recent sessions title color</li><li>Fix project dropdown labels and sorting order</li><li>Move left panel toggle button to the right</li><li>Fix avatar background color</li><li>Show project options on hover of row</li><li>Increase delay on session list tooltips</li><li>Fix tooltip gutter spacing on session items and archive buttons</li><li>Archive icon replaces diff count on hover</li><li>Fix hover state for recent sessions in gutter</li><li>Fix search bar functionality in header</li><li>Fixed layout issues in the app</li><li>Fix stale sessions in new layout</li><li>New app layout</li><li>Open external links in system browser instead of webview in desktop app</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const g=t(r,[["render",s]]);export{m as __pageData,g as default};
